/// <summary>
/// The controller of Bag marking ER report
/// </summary>
class ETG_BagMarkingERController extends ERFormatMappingRunBaseController
{
}

Method.Source:
/// <summary>
/// The main entrance of the controller
/// </summary>
/// <param name = "_args">The arguments</param>
public static void main(Args _args)
{
    AgreementConfirmationRDPContract contract;
    SalesAgreementHeader             agreementHeader;

    if (_args.dataset() == tableNum(SalesAgreementHeader))
    {
        agreementHeader = _args.record();
        contract = new AgreementConfirmationRDPContract();
        contract.parmRecordId(agreementHeader.RecId);

    }

    if (contract.parmRecordId())
    {
        ETG_BagMarkingERService::generateReportByGER(contract);
    }
}

/// <summary>
/// Gets caption of the dialog.
/// </summary>
/// <returns>Caption of the dialog</returns>
public ClassDescription defaultCaption()
{
    return "Bag Marking";
}
